parameters.jsCode:
const raw = $input.first().json;

let body = {};
try {
  body = $('Webhook1').first().json.body;
} catch(e) {
  try {
    body = $('Webhook').first().json.body;
  } catch(e2) {
    body = {};
  }
}

let redisData = null;
try {
  if (raw?.result) {
    redisData = typeof raw.result === 'string' ? JSON.parse(raw.result) : raw.result;
  }
} catch(e) { redisData = null; }

const session_id      = body.session_id || 'default_session';
const current_message = body.commande   || body.message || '';
const selection       = body.selection  || null;

// ✅ FIX CRITIQUE : Détecter une nouvelle commande
// Si le message commence par "COMMANDE :" ou si une sélection arrive
// ET que l'ancienne session est confirmée → on reset Redis
const isNewOrder = 
  current_message.toUpperCase().startsWith('COMMANDE :') ||
  (selection !== null && selection !== undefined);

if (isNewOrder && redisData?.confirmed === true) {
  // ✅ Reset forcé : nouvelle commande = nouvelle session
  redisData = null;
}

const default_user_info = {
  prenom: null, nom: null, email: null, password: null,
  adresse: null, code_postal: null, ville: null, telephone: null,
  mode_livraison: null, mode_paiement: null
};

const user_info = { ...default_user_info, ...(redisData?.user_info || {}) };
const ui        = user_info;

const product  = selection?.name || redisData?.product  || null;
const quantity = selection?.qty  || redisData?.quantity || null;

const isComplete = !!(
  product && quantity &&
  ui.prenom && ui.nom && ui.email && ui.password &&
  ui.adresse && ui.ville && ui.code_postal
);

const confirmedInRedis = redisData?.confirmed            === true;
const waitingInRedis   = redisData?.waiting_confirmation === true;
const waiting_confirmation = waitingInRedis || (isComplete && !confirmedInRedis);

return {
  session_id,
  current_message,
  product,
  quantity,
  product_id:            selection?.id    || redisData?.product_id    || null,
  product_price:         selection?.price || redisData?.product_price || null,
  intent:                redisData?.intent      || 'commande',
  last_intent:           redisData?.last_intent || null,
  customer_id:           redisData?.customer_id || null,
  address_id:            redisData?.address_id  || null,
  user_info,
  confirmed:             confirmedInRedis,
  waiting_confirmation,
  session_source:        redisData ? 'redis' : 'new',
  id_carrier:            redisData?.id_carrier    || null,
  carrier_name:          redisData?.carrier_name  || null,
  payment_module:        redisData?.payment_module || null,
  payment_label:         redisData?.payment_label  || null,
  // ✅ FIX boucle infinie : next_field restauré depuis Redis
  next_field:            isNewOrder ? null : (redisData?.next_field || null),
  // ✅ FIX : Indicateur nouvelle commande pour Code in JavaScript
  is_new_order:          isNewOrder
};
